import { Mesh } from 'three';
import { WebGLRenderer } from 'three';

/**
 * Create an instance of the Evercoast player api
 * @public
 *
 * @example
 * ```ts
 * const renderer = new THREE.WebGLRenderer();
 * const scene = new THREE,Scene();
 * const playerApi = createPlayerApi(renderer);
 * playerApi.open('content.ecm')
 *     .then(mesh => {
 *         scene.add(mesh);
 *     });
 * ```
 *
 * @param renderer - ThreeJS WebGL 1 or 2 renderer
 * @param config - Modifiy player api default behaviour
 *
 * @returns Evercoast Player API used to open and control playback of Evercoast content
 * */
export declare const createPlayerApi: (renderer: WebGLRenderer, config?: PlayerApiConfig) => ThreeJSPlayerApi;

/**
 * @public
 */
export declare class EventDispatcher<E> {
    private handlers;
    /** Dispatch event on all listeners */
    dispatch(event: E): void;
    /** Add event listener */
    add(handler: (event: E) => void, signal?: AbortSignal): void;
    /** Remove event listener */
    remove(handler: (event: E) => void): void;
    clear(): void;
}

/** @public */
export declare enum PlaybackErrorReason {
    CONTENT_NOT_SPECIFIED = "CONTENT NOT SPECIFIED",
    CONTENT_NOT_AVAILABLE = "CONTENT NOT AVAILABLE",
    FAILED_TO_READ_STREAM = "FAILED TO READ STREAM",
    CACHE_ERROR = "CACHE ERROR",
    FAILED_TO_BEGIN_PLAYBACK = "FAILED TO BEGIN PLAYBACK"
}

/**
 * Open and control playback of Evercoast content
 * @public
 */
export declare interface PlayerApi<MeshType> {
    /**
     * Open content, once complete content is ready to begin playback
     * @example
     * ```
     * playerApi.open('https://streaming.evercoast.com/example/LIZA-TRAP.30FPS.ec.take.002.audio.ecm')
     * ```
     * @param source - URI of Evercoast ECM content
     * @param readConfig - Override download and caching settings
     * @returns - Promise with mesh that will be resolved when first frame is ready
     */
    open(source: string, readConfig?: Partial<ReaderConfig>): Promise<MeshType>;
    /**
     * Close content, playback will no longer be possible
     * @param keepMeshAlive - Defaults to false, allow the continued use of the last frame applied to mesh. If true, mesh must be released manually.
     */
    close(keepMeshAlive?: boolean): void;
    /**
     * Triggered when metadata is loaded from the ECM,
     * `readConfig.requestMetaData` must be true.
     */
    onMetaData: EventDispatcher<{
        [key: string]: string;
    }>;
    /** Triggered when playback is first started. */
    onStarted: EventDispatcher<void>;
    /** Triggered when playback is paused. */
    onPaused: EventDispatcher<void>;
    /** Triggered when playback is resumed. */
    onResumed: EventDispatcher<void>;
    /** Triggered when playback seeks to a new time. */
    onSeek: EventDispatcher<number>;
    /**
     * Triggered when playback has finished seeking to a new time
     * Will only be triggered once if seek is called again before
     * first finishes.
     */
    onSeeked: EventDispatcher<void>;
    /**
     * Triggered when playback finishes
     * Will not be triggered if looping is enabled
     */
    onEnded: EventDispatcher<void>;
    /** Triggered if looping is enabled, and playback reaches end of clip  */
    onLoop: EventDispatcher<void>;
    /** Triggered when caption should be displayed */
    onCue: EventDispatcher<VTTCue | null>;
    /** Triggered when a live stream is loaded or the live stream ends */
    onLiveStateChange: EventDispatcher<{
        isLive: boolean;
    }>;
    /** Triggered if an error occurs during loading or playback */
    onError: EventDispatcher<PlaybackErrorReason>;
    /** Triggered when rendering mesh is created */
    onMeshCreated: EventDispatcher<MeshType>;
    /** Triggered when rendering mesh is destroyed */
    onMeshDestroyed: EventDispatcher<MeshType>;
    /** Similar to HTMLMediaElement, see https://developer.mozilla.org/en-US/docs/Web/API/HTMLMediaElement/readyState */
    get readyState(): number;
    /** Current time of playback */
    get currentTime(): number;
    /** Current frame number being rendered */
    get currentFrameNumber(): number;
    /** Current number of geometry primitives (triangles / splats / voxels) */
    get currentPrimitiveCount(): number;
    /** Frame rate of loaded content */
    get frameRate(): number;
    /** Duration of cached and ready to playback content */
    get cacheEndTime(): number;
    /** Duration of ECM */
    get duration(): number;
    /** Is the ECM currently playing */
    get isPlaying(): boolean;
    /**
     * Is playback currently paused, may be true if either `pause()` is called
     * or if the system is waiting for more content to be downloaded
     */
    get isPaused(): boolean;
    /**
     * Is the playback system currently in a seeking state,
     * playback should be avoided at this time.
     */
    get isSeeking(): boolean;
    /** Control the playback speed */
    get playbackRate(): number;
    set playbackRate(value: number);
    /** Does the ECM have audio */
    get hasAudio(): boolean;
    /** Control audio mute state*/
    get muted(): boolean;
    set muted(value: boolean);
    /** Control audio volume, defaults to 1 */
    get volume(): number;
    set volume(value: number);
    /** Control is the ECM should loop */
    get loop(): boolean;
    set loop(value: boolean);
    /** Control  */
    /** Is playback streaming from a live source */
    get isLive(): boolean;
    get hasSingleFrame(): boolean | undefined;
    /** Get render mesh, only valid after "open" completes */
    get mesh(): MeshType | null;
    /** Get metadata, metaData must be enabled in `open` `readConfig` */
    get metaData(): {
        [key: string]: string;
    } | undefined;
    get geometryBitrate(): number;
    get textureBitrate(): number;
    get error(): PlaybackErrorReason | undefined;
    get originalFrameRate(): number;
    get originalFrameRange(): {
        start: number;
        end: number;
    };
    /**
     * Begin playback
     * If the ECM contains audio, the first called to `play()` must
     * happen during a user interaction event.
     */
    play(): Promise<void>;
    /** Pause playback */
    pause(): void;
    /** Seek to a new time */
    seek(time: number): boolean;
    /** load WebVTT subtitles, once loaded will be output `onCue` event */
    loadTextTrack(opts?: {
        lang?: string;
        url?: string;
    }): Promise<void>;
    removeTextTrack(): void;
    /** Update playback state */
    update(): boolean;
}

/** @public */
export declare class PlayerApiConfig {
    /** search path for external scripts such as decode .worker.js */
    root: string;
    /** Desired bitrate of loaded content */
    maxBitrate: number;
    /** Desired framerate of loaded content */
    maxFramerate: number;
}

/** @public */
export declare interface ReaderConfig {
    initialRequestDuration: number;
    maxRequestDuration: number;
    initialCacheDuration: number;
    maxCacheAheadDuration: number;
    maxCacheMemorySize: number;
    formatGuess: number;
    debugLogging: boolean;
    requestMetaData: boolean;
    progressiveDownload: boolean;
}

/** @public */
export declare type ThreeJSPlayerApi = PlayerApi<Mesh>;

